   public void refreshDisplay()
   {
       next refreshDisplay();

       if (!KJP_CM_Utils::checkCurExtIsKKC())
       {
           return;
       }

       InventTable_DS_PropertyId.visible(true);
       InventTable_DS_KJPCMSupervisingDepartment.visible(true);

       if (this.inventDimSetupObject().parmDimParmVisibleGrid().InventBatchIdFlag == NoYes::No)
       {
           InventBatch_KJPSMReservationControlFlag.visible(false);
       }
       else
       {
           InventBatch_KJPSMReservationControlFlag.visible(true);
       }
   }
